#!/usr/bin/env python3
"""Full CTA1024 W4A4 scattered-activation co-design sweep.

One file owns the CUDA source, build, exact-live l2pfAct routing sweep,
rectangular CSV validation, and paired TMA-baseline summary.

Colab terminal:
  colab exec -s xCalibrr -f experiments/ff1_w4a4_scattered_exp.py --timeout 3600

Focused run:
  python3 experiments/ff1_w4a4_scattered_exp.py --N 256 \
      --live-experts 384 --repeats 20
"""

from __future__ import annotations

import argparse
import base64
import csv
import math
import os
import shlex
import statistics
import subprocess
from pathlib import Path


CUDA_B64 = ""

MODES = [
    "no_pf_tma_smem",
    "pf32x4_n256_tma_smem",
    "no_pf_cp_async_ca_smem",
    "pf32x4_n256_cp_async_ca_smem",
]


def command_text(command: list[str]) -> str:
    return " ".join(shlex.quote(x) for x in command)


def run(command: list[str]) -> None:
    print("+", command_text(command), flush=True)
    subprocess.run(command, check=True)


def u32_list(raw: str, flag: str) -> list[int]:
    try:
        values = [int(x.strip(), 0) for x in raw.split(",") if x.strip()]
    except ValueError as exc:
        raise SystemExit(f"{flag}: expected comma-separated integers") from exc
    if not values:
        raise SystemExit(f"{flag}: empty")
    return list(dict.fromkeys(values))


def live_map(raw: str) -> dict[int, list[int]]:
    result: dict[int, list[int]] = {}
    try:
        for group in raw.split(","):
            n_raw, live_raw = group.split(":", 1)
            N = int(n_raw.strip(), 0)
            values = [int(x.strip(), 0) for x in live_raw.split("|") if x.strip()]
            if N in result or not values:
                raise ValueError
            result[N] = list(dict.fromkeys(values))
    except ValueError as exc:
        raise SystemExit(
            "--sweep-live: expected N:live|live groups, for example "
            "8:8|64,256:128|384,512:128|384"
        ) from exc
    if not result:
        raise SystemExit("--sweep-live: empty")
    return result


def validate_csv(path: Path) -> list[dict[str, str]]:
    with path.open(newline="", encoding="utf-8") as f:
        reader = csv.DictReader(f)
        if not reader.fieldnames or len(reader.fieldnames) != len(set(reader.fieldnames)):
            raise SystemExit(f"{path}: invalid CSV header")
        rows = list(reader)
    if not rows:
        raise SystemExit(f"{path}: no rows")

    checksums: dict[tuple[str, str, str], set[str]] = {}
    for line, row in enumerate(rows, 2):
        if row["status"] != "PASS":
            raise SystemExit(f"{path}:{line}: kernel status {row['status']}")
        if int(row["blocks_per_sm"]) != 1:
            raise SystemExit(f"{path}:{line}: blocks_per_sm != 1")
        if row["routing"] != "balanced_exact_live_scattered":
            raise SystemExit(f"{path}:{line}: wrong routing contract")
        N, I, H = int(row["N"]), int(row["I"]), int(row["H"])
        E = int(row["E"])
        target = int(row["live_expert_target"])
        live = int(row["live_experts"])
        assignments = int(row["assignments"])
        active_n8 = int(row["active_n8_tiles"])
        k64, i_count = H // 64, I // 1024
        if assignments != N * 8:
            raise SystemExit(f"{path}:{line}: assignments != N*TOPK")
        if target < 8 or target > min(E, assignments) or live != target:
            raise SystemExit(
                f"{path}:{line}: exact-live invariant target={target}, live={live}"
            )
        if int(row["min_tokens_per_live_expert"]) != assignments // target:
            raise SystemExit(f"{path}:{line}: bad minimum route balance")
        if int(row["max_tokens_per_live_expert"]) != (
            assignments + target - 1
        ) // target:
            raise SystemExit(f"{path}:{line}: bad maximum route balance")
        expected = {
            "smem_bytes": N * 72 + 1024 * 16,
            "n256_count": (N + 255) // 256,
            "x4_global_bytes": assignments * k64 * 32,
            "sx_global_bytes": assignments * k64 * 4,
            "W_bytes": int(row["live_experts"]) * k64 * i_count * 65536,
            "S_bytes": int(row["live_experts"]) * k64 * i_count * 8192,
            "partial_load_bytes": active_n8 * (k64 - 1) * i_count * 32768,
            "partial_store_bytes": active_n8 * (k64 - 1) * i_count * 32768,
            "final_reduce_bytes": active_n8 * I * 16,
            "Y_workspace_bytes": (int(row["E"]) * 2 * I * N + I * N) * 2,
            "mma_inst": active_n8 * i_count * k64 * 4 * 32,
        }
        for key, value in expected.items():
            if int(row[key]) != value:
                raise SystemExit(
                    f"{path}:{line}: {key}={row[key]}, expected {value}"
                )
        pf_expected = 0 if row["prefetch"] == "none" else (
            assignments * (k64 * 32 + (k64 // 8) * 32)
        )
        if int(row["pf_requested_bytes"]) != pf_expected:
            raise SystemExit(f"{path}:{line}: bad prefetch byte count")
        if float(row["kernel_ms"]) <= 0 or float(row["max_rel_err"]) > 0.02:
            raise SystemExit(f"{path}:{line}: timing or correctness failure")
        checksums.setdefault(
            (row["N"], row["live_expert_target"], row["route_seed"]), set()
        ).add(row["checksum"])
    if any(len(values) != 1 for values in checksums.values()):
        raise SystemExit(f"{path}: equal-work mode checksum mismatch")
    return rows


def native_command(
    args: argparse.Namespace,
    exe: Path,
    csv_path: Path,
    N: int,
    live: int,
    seed: int,
    repeats: int,
) -> list[str]:
    return [
        str(exe),
        "--E", str(args.E),
        "--N", str(N),
        "--I", str(args.I),
        "--H", str(args.H),
        "--active-experts", str(live),
        "--route-seed", hex(seed),
        "--repeats", str(repeats),
        "--methods", args.methods,
        "--csv", str(csv_path),
    ]


def write_csv(path: Path, rows: list[dict[str, str]]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=list(rows[0]))
        writer.writeheader()
        writer.writerows(rows)


def summarize(rows: list[dict[str, str]], out_dir: Path) -> None:
    baselines = {
        (r["N"], r["live_expert_target"], r["route_seed"]): float(r["kernel_ms"])
        for r in rows if r["mode"] == "no_pf_tma_smem"
    }
    grouped: dict[tuple[str, str, str], list[dict[str, str]]] = {}
    for row in rows:
        grouped.setdefault(
            (row["N"], row["live_expert_target"], row["mode"]), []
        ).append(row)

    summary: list[dict[str, str]] = []
    for (N, live, mode), group in sorted(
        grouped.items(), key=lambda x: (int(x[0][0]), int(x[0][1]), MODES.index(x[0][2]))
    ):
        times = [float(r["kernel_ms"]) for r in group]
        reductions = [
            100.0 * (1.0 - float(r["kernel_ms"])
                     / baselines[(N, live, r["route_seed"])])
            for r in group
        ]
        summary.append({
            "N": N,
            "live_expert_target": live,
            "mode": mode,
            "transport": group[0]["transport"],
            "prefetch": group[0]["prefetch"],
            "seeds": str(len(group)),
            "live_experts_min": str(min(int(r["live_experts"]) for r in group)),
            "live_experts_max": str(max(int(r["live_experts"]) for r in group)),
            "tokens_per_live_expert_min": str(min(
                int(r["min_tokens_per_live_expert"]) for r in group
            )),
            "tokens_per_live_expert_max": str(max(
                int(r["max_tokens_per_live_expert"]) for r in group
            )),
            "active_n8_tiles_min": str(min(int(r["active_n8_tiles"]) for r in group)),
            "active_n8_tiles_max": str(max(int(r["active_n8_tiles"]) for r in group)),
            "median_ms": f"{statistics.median(times):.6f}",
            "min_ms": f"{min(times):.6f}",
            "max_ms": f"{max(times):.6f}",
            "median_reduction_vs_tma0_pct": f"{statistics.median(reductions):.4f}",
            "median_useful_tflops":
                f"{statistics.median(float(r['useful_tflops']) for r in group):.6f}",
            "median_issued_tflops":
                f"{statistics.median(float(r['issued_mma_tflops']) for r in group):.6f}",
            "mma_useful_pct": group[0]["mma_useful_pct"],
        })
    write_csv(out_dir / "summary.csv", summary)

    print()
    print("+-----+------+--------------------------------------------+----------+----------+----------+----------+")
    print("| N   | live | mode                                       | med ms   | vs TMA0  | usefulTF | issuedTF |")
    print("+-----+------+--------------------------------------------+----------+----------+----------+----------+")
    for row in summary:
        print(
            f"| {int(row['N']):3d} | {int(row['live_expert_target']):4d} | "
            f"{row['mode']:<42} | {float(row['median_ms']):8.3f} | "
            f"{float(row['median_reduction_vs_tma0_pct']):+7.2f}% | "
            f"{float(row['median_useful_tflops']):8.2f} | "
            f"{float(row['median_issued_tflops']):8.2f} |"
        )
    print("+-----+------+--------------------------------------------+----------+----------+----------+----------+")

    print("\nPaired winners:")
    for N, live in sorted({(r["N"], r["live_expert_target"]) for r in summary},
                          key=lambda x: (int(x[0]), int(x[1]))):
        part = [
            r for r in summary
            if r["N"] == N and r["live_expert_target"] == live
        ]
        best = max(part, key=lambda r: (
            float(r["median_reduction_vs_tma0_pct"]), -float(r["median_ms"])
        ))
        print(
            f"  N={N:>3} live={live:>3}  {best['mode']}  "
            f"{float(best['median_ms']):.3f} ms  "
            f"{float(best['median_reduction_vs_tma0_pct']):+.2f}% vs TMA0"
        )


def parse_args() -> argparse.Namespace:
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("-f", dest="_jupyter_connection_file", help=argparse.SUPPRESS)
    ap.add_argument("--arch", default="sm_120a")
    ap.add_argument("--nvcc", default=os.environ.get("NVCC", "nvcc"))
    ap.add_argument("--workdir", type=Path,
                    default=Path("/content/xcaliber_ff1_w4a4_scattered"))
    ap.add_argument("--csv", type=Path,
                    default=Path("/content/ff1_w4a4_scattered.csv"))
    ap.add_argument("--E", type=int, default=384)
    ap.add_argument("--N", type=int, default=256)
    ap.add_argument("--I", type=int, default=2048)
    ap.add_argument("--H", type=int, default=7168)
    ap.add_argument("--live-experts", "--active-experts", dest="live_experts",
                    type=int, default=384)
    ap.add_argument("--route-seed", type=lambda x: int(x, 0), default=0x6A09E667)
    ap.add_argument("--repeats", type=int, default=20)
    ap.add_argument("--methods", default="all")
    ap.add_argument("--sweep", action="store_true")
    ap.add_argument("--sweep-n", default="8,256,512")
    ap.add_argument("--sweep-live",
                    default="8:8|64,256:128|384,512:128|384")
    ap.add_argument("--sweep-seeds",
                    default="0x6a09e667,0xbb67ae85,0x3c6ef372")
    ap.add_argument("--sweep-repeats", type=int, default=20)
    ap.add_argument("--sweep-dir", type=Path,
                    default=Path("/content/ff1_w4a4_scattered_sweep"))
    ap.add_argument("--quick", action="store_true")
    ap.add_argument("--compile-only", action="store_true")
    ap.add_argument("--no-build", action="store_true")
    ap.add_argument("--dry-run", action="store_true")
    return ap.parse_args()


def main() -> int:
    args = parse_args()
    if args._jupyter_connection_file and not args.quick:
        args.sweep = True
    selected = MODES if args.methods == "all" else [
        x.strip() for x in args.methods.split(",") if x.strip()
    ]
    unknown = [x for x in selected if x not in MODES]
    if unknown:
        raise SystemExit(f"--methods: unknown {','.join(unknown)}")
    args.methods = ",".join(selected)

    if args.quick:
        args.E, args.N, args.I, args.H = 16, 8, 1024, 128
        args.live_experts, args.repeats = 16, 2
        args.sweep = False

    source = base64.b64decode(CUDA_B64).decode("ascii")
    if source.count("mma.sync.aligned.m16n8k64") != 4:
        raise SystemExit("source audit: expected four MMA issue sites")
    if source.count("__syncthreads()") != 1:
        raise SystemExit("source audit: expected one cold CTA barrier")
    for required in (
        "cp.async.bulk.prefetch.L2.global [%0], 32",
        "cp.async.ca.shared.global",
        "mbarrier.arrive.expect_tx.release.cta",
        "mbarrier.test_wait.acquire.cta",
        "ldu.global.u32",
        "fma.rn.bf16x2",
        "ld.shared.u32",
        "balanced_exact_live_scattered",
    ):
        if required not in source:
            raise SystemExit(f"source audit: missing {required}")

    args.workdir.mkdir(parents=True, exist_ok=True)
    cu = args.workdir / "ff1_w4a4_scattered_codesign.cu"
    exe = args.workdir / "ff1_w4a4_scattered"
    cu.write_text(source, encoding="ascii")
    build = [
        args.nvcc, "-O3", "-std=c++17", f"-arch={args.arch}", "-lineinfo",
        "-Xptxas=-v", str(cu), "-o", str(exe),
    ]
    if args.dry_run:
        print("+", command_text(build))
    elif not args.no_build:
        run(build)
    elif not exe.is_file():
        raise SystemExit(f"--no-build executable missing: {exe}")
    if args.compile_only:
        return 0

    if not args.sweep:
        command = native_command(
            args, exe, args.csv, args.N, args.live_experts,
            args.route_seed, args.repeats,
        )
        if args.dry_run:
            print("+", command_text(command))
            return 0
        run(command)
        rows = validate_csv(args.csv)
        summarize(rows, args.csv.parent)
        print(f"CSV: {args.csv}")
        return 0

    Ns = u32_list(args.sweep_n, "--sweep-n")
    lives = live_map(args.sweep_live)
    seeds = u32_list(args.sweep_seeds, "--sweep-seeds")
    args.sweep_dir.mkdir(parents=True, exist_ok=True)
    all_rows: list[dict[str, str]] = []
    for N in Ns:
        if N not in lives:
            raise SystemExit(f"--sweep-live has no entry for N={N}")
        for live in lives[N]:
            if live < 8 or live > min(args.E, N * 8):
                raise SystemExit(f"invalid exact live count N={N}, live={live}")
            for seed in seeds:
                path = args.sweep_dir / f"N{N}_live{live}_seed{seed:08x}.csv"
                command = native_command(
                    args, exe, path, N, live, seed, args.sweep_repeats,
                )
                if args.dry_run:
                    print("+", command_text(command))
                    continue
                print(f"\n=== {path.stem} ===", flush=True)
                run(command)
                all_rows.extend(validate_csv(path))
    if args.dry_run:
        return 0
    write_csv(args.sweep_dir / "combined.csv", all_rows)
    summarize(all_rows, args.sweep_dir)
    print(f"Combined CSV: {args.sweep_dir / 'combined.csv'}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
